export interface FileState {
  file: File | Blob | null;
  previewUrl: string | null;
  name: string;
}

export enum RenderStatus {
  IDLE = 'IDLE',
  GENERATING_IMAGE = 'GENERATING_IMAGE',
  GENERATING_AUDIO = 'GENERATING_AUDIO',
  PREPARING = 'PREPARING',
  RENDERING = 'RENDERING',
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR'
}

export interface RenderingProgress {
  status: RenderStatus;
  progress: number;
  message: string;
}

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, Modality } from "@google/genai";
import FileUploader from './components/FileUploader';
import { FileState, RenderStatus, RenderingProgress } from './types';

const App: React.FC = () => {
  const [image, setImage] = useState<FileState>({ file: null, previewUrl: null, name: '' });
  const [audio, setAudio] = useState<FileState>({ file: null, previewUrl: null, name: '' });
  const [imagePrompt, setImagePrompt] = useState('');
  const [audioPrompt, setAudioPrompt] = useState('');
  const [agreed, setAgreed] = useState(false);
  const [renderStatus, setRenderStatus] = useState<RenderingProgress>({
    status: RenderStatus.IDLE,
    progress: 0,
    message: ''
  });
  const [resultVideoUrl, setResultVideoUrl] = useState<string | null>(null);
  const [currentTimeFormatted, setCurrentTimeFormatted] = useState('0:00');
  const [totalTimeFormatted, setTotalTimeFormatted] = useState('0:00');

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const audioRef = useRef<HTMLAudioElement>(null);
  const renderLoopRef = useRef<number | null>(null);
  const wakeLockRef = useRef<any>(null);

  const formatTime = (seconds: number) => {
    if (isNaN(seconds) || !isFinite(seconds)) return '0:00';
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const requestWakeLock = async () => {
    if ('wakeLock' in navigator) {
      try { wakeLockRef.current = await (navigator as any).wakeLock.request('screen'); } catch (e) {}
    }
  };

  const generateAIImage = async () => {
    if (!imagePrompt) return;
    setRenderStatus({ status: RenderStatus.GENERATING_IMAGE, progress: 30, message: 'Painting your vision...' });
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: imagePrompt }] },
        config: { imageConfig: { aspectRatio: "16:9" } }
      });

      let base64 = '';
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          base64 = part.inlineData.data;
          break;
        }
      }

      if (base64) {
        const blob = await (await fetch(`data:image/png;base64,${base64}`)).blob();
        setImage({
          file: blob,
          previewUrl: URL.createObjectURL(blob),
          name: `AI_Generated_${Date.now()}.png`
        });
        setRenderStatus({ status: RenderStatus.IDLE, progress: 0, message: '' });
      }
    } catch (err) {
      console.error(err);
      setRenderStatus({ status: RenderStatus.ERROR, progress: 0, message: 'Image Generation Failed' });
    }
  };

  const decodeAudioData = async (data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number): Promise<AudioBuffer> => {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) {
        channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
      }
    }
    return buffer;
  };

  const decodeBase64 = (base64: string) => {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  };

  const generateAIAudio = async () => {
    if (!audioPrompt) return;
    setRenderStatus({ status: RenderStatus.GENERATING_AUDIO, progress: 30, message: 'Synthesizing voice...' });
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: audioPrompt }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) {
        // Convert raw PCM to a playable WAV Blob
        const audioBytes = decodeBase64(base64Audio);
        const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        const audioBuffer = await decodeAudioData(audioBytes, audioCtx, 24000, 1);

        // Use an offline helper to encode to WAV for better browser support
        const blob = await bufferToWavBlob(audioBuffer);
        setAudio({
          file: blob,
          previewUrl: URL.createObjectURL(blob),
          name: `AI_Voice_${Date.now()}.wav`
        });
        setRenderStatus({ status: RenderStatus.IDLE, progress: 0, message: '' });
      }
    } catch (err) {
      console.error(err);
      setRenderStatus({ status: RenderStatus.ERROR, progress: 0, message: 'Audio Generation Failed' });
    }
  };

  // Helper for converting AudioBuffer to Wav Blob
  const bufferToWavBlob = async (buffer: AudioBuffer): Promise<Blob> => {
    const numOfChan = buffer.numberOfChannels;
    const length = buffer.length * numOfChan * 2 + 44;
    const outBuffer = new ArrayBuffer(length);
    const view = new DataView(outBuffer);
    const sampleRate = buffer.sampleRate;

    const writeString = (view: DataView, offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) {
        view.setUint8(offset + i, string.charCodeAt(i));
      }
    };

    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + buffer.length * numOfChan * 2, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, numOfChan, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, sampleRate * 2 * numOfChan, true);
    view.setUint16(32, numOfChan * 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, buffer.length * numOfChan * 2, true);

    let offset = 44;
    for (let i = 0; i < buffer.length; i++) {
      for (let channel = 0; channel < numOfChan; channel++) {
        const sample = Math.max(-1, Math.min(1, buffer.getChannelData(channel)[i]));
        view.setInt16(offset, sample < 0 ? sample * 0x8000 : sample * 0x7FFF, true);
        offset += 2;
      }
    }
    return new Blob([outBuffer], { type: 'audio/wav' });
  };

  const startConversion = async () => {
    if (!image.file || !audio.file || !audioRef.current || !agreed) return;

    try {
      setRenderStatus({
        status: RenderStatus.RENDERING,
        progress: 1,
        message: 'Initializing Cinema Engine...'
      });

      await requestWakeLock();

      const canvas = canvasRef.current!;
      const ctx = canvas.getContext('2d', { alpha: false })!;

      // Standard HD resolution
      canvas.width = 1280;
      canvas.height = 720;

      const img = new Image();
      img.src = image.previewUrl!;
      await new Promise((r) => img.onload = r);

      const AudioContextClass = (window.AudioContext || (window as any).webkitAudioContext);
      const audioCtx = new AudioContextClass();
      const source = audioCtx.createMediaElementSource(audioRef.current);
      const dest = audioCtx.createMediaStreamDestination();
      source.connect(dest);

      // Higher FPS (24) for smooth video on phone. 
      // Recording happens in real-time to match audio duration perfectly.
      const videoStream = canvas.captureStream(24); 
      const combinedStream = new MediaStream([
        ...videoStream.getVideoTracks(),
        ...dest.stream.getAudioTracks()
      ]);

      const mimeType = ['video/mp4', 'video/webm;codecs=h264', 'video/webm'].find(t => MediaRecorder.isTypeSupported(t)) || 'video/webm';
      const recorder = new MediaRecorder(combinedStream, { 
        mimeType, 
        videoBitsPerSecond: 2500000 
      });

      const chunks: Blob[] = [];
      recorder.ondataavailable = (e) => chunks.push(e.data);
      recorder.onstop = () => {
        const finalBlob = new Blob(chunks, { type: mimeType });
        const url = URL.createObjectURL(finalBlob);
        setResultVideoUrl(url);
        setRenderStatus({ status: RenderStatus.COMPLETED, progress: 100, message: 'Mastered!' });
        if (wakeLockRef.current) wakeLockRef.current.release();
      };

      const draw = () => {
        if (!ctx) return;

        ctx.fillStyle = '#000';
        ctx.fillRect(0, 0, 1280, 720);

        // Subtle pan/zoom effect for "Cinematic Motion"
        const time = audioRef.current?.currentTime || 0;
        const scale = 1.0 + (Math.sin(time * 0.1) * 0.05); // 5% zoom pulse

        const ratio = Math.max(1280 / img.width, 720 / img.height) * scale;
        const w = img.width * ratio;
        const h = img.height * ratio;

        const offsetX = (1280 - w) / 2 + (Math.cos(time * 0.15) * 20); // Subtle pan
        const offsetY = (720 - h) / 2 + (Math.sin(time * 0.1) * 20);

        ctx.drawImage(img, offsetX, offsetY, w, h);

        if (audioRef.current) {
          const cur = audioRef.current.currentTime;
          const dur = audioRef.current.duration;
          const p = Math.floor((cur / dur) * 100);

          setCurrentTimeFormatted(formatTime(cur));
          setTotalTimeFormatted(formatTime(dur));

          setRenderStatus(prev => ({ 
            status: RenderStatus.RENDERING,
            progress: Math.min(99, Math.max(1, p)),
            message: `Rendering: ${formatTime(cur)} / ${formatTime(dur)}`
          }));

          if (audioRef.current.ended || cur >= dur) {
            recorder.stop();
            audioRef.current.pause();
            if (renderLoopRef.current) cancelAnimationFrame(renderLoopRef.current);
            return;
          }
        }
        renderLoopRef.current = requestAnimationFrame(draw);
      };

      // Set playback rate to 1.0 to ENSURE the duration matches the original MP3
      audioRef.current.currentTime = 0;
      audioRef.current.playbackRate = 1.0; 
      audioRef.current.muted = false; // Need audio unmuted for dest.stream

      await audioCtx.resume();
      await audioRef.current.play();
      recorder.start();
      draw();

    } catch (err) {
      console.error(err);
      setRenderStatus({ status: RenderStatus.ERROR, progress: 0, message: 'Processing Error. Please reload.' });
    }
  };

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-100 flex flex-col font-sans">
      <header className="bg-slate-900/50 backdrop-blur-xl sticky top-0 z-50 border-b border-white/5 p-5 flex flex-col items-center gap-1 shadow-2xl">
        <div className="flex items-center gap-2">
          <div className="w-10 h-10 bg-gradient-to-tr from-indigo-500 to-purple-500 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
             <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
          </div>
          <h1 className="text-xl font-black tracking-tight text-white uppercase italic">VocalCanvas</h1>
        </div>
        <p className="text-[9px] text-slate-400 font-bold tracking-[0.3em] uppercase opacity-60">Creative Studio • v4.0</p>
      </header>

      <main className="flex-1 max-w-xl mx-auto w-full px-5 py-8 space-y-10">
        {(renderStatus.status === RenderStatus.IDLE || renderStatus.status === RenderStatus.GENERATING_IMAGE || renderStatus.status === RenderStatus.GENERATING_AUDIO) && !resultVideoUrl && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">

            {/* IMAGE SECTION */}
            <section className="space-y-4">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <span className="w-8 h-8 bg-indigo-500 text-white rounded-lg flex items-center justify-center text-sm font-black shadow-lg shadow-indigo-500/20 italic">1</span>
                  <h2 className="text-sm font-black uppercase tracking-widest text-slate-300">Visual Background</h2>
                </div>
              </div>

              <div className="bg-slate-900/40 rounded-3xl p-6 border border-white/5 shadow-inner space-y-6">
                <div className="flex flex-col gap-3">
                  <div className="relative group">
                    <textarea 
                      placeholder="Or describe an image for AI to paint..."
                      className="w-full bg-slate-950/50 border border-white/10 rounded-2xl p-4 text-sm focus:ring-2 focus:ring-indigo-500 outline-none min-h-[80px] transition-all"
                      value={imagePrompt}
                      onChange={(e) => setImagePrompt(e.target.value)}
                    />
                    <button 
                      onClick={generateAIImage}
                      disabled={!imagePrompt || renderStatus.status !== RenderStatus.IDLE}
                      className="absolute bottom-3 right-3 p-2 bg-indigo-500 rounded-xl hover:bg-indigo-400 transition-colors disabled:opacity-50"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                    </button>
                  </div>
                  <p className="text-[10px] text-center text-slate-500 font-bold uppercase tracking-widest">— OR —</p>
                  <FileUploader 
                    label="Upload Custom Image" 
                    accept="image/*" 
                    selectedFileName={image.name}
                    onFileSelect={(f) => setImage({ file: f, previewUrl: URL.createObjectURL(f), name: f.name })}
                    icon={<svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>} 
                  />
                </div>
                {image.previewUrl && (
                  <div className="relative aspect-video rounded-2xl overflow-hidden border border-indigo-500/30 shadow-2xl">
                    <img src={image.previewUrl} className="w-full h-full object-cover" alt="Preview" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent flex items-end p-4">
                      <span className="text-[10px] font-black text-white/80 uppercase tracking-widest">Selected Image Ready</span>
                    </div>
                  </div>
                )}
              </div>
            </section>

            {/* AUDIO SECTION */}
            <section className="space-y-4">
              <div className="flex items-center gap-3">
                <span className="w-8 h-8 bg-purple-500 text-white rounded-lg flex items-center justify-center text-sm font-black shadow-lg shadow-purple-500/20 italic">2</span>
                <h2 className="text-sm font-black uppercase tracking-widest text-slate-300">Audio Track</h2>
              </div>

              <div className="bg-slate-900/40 rounded-3xl p-6 border border-white/5 shadow-inner space-y-6">
                <div className="flex flex-col gap-3">
                  <div className="relative group">
                    <textarea 
                      placeholder="Type text for AI to speak..."
                      className="w-full bg-slate-950/50 border border-white/10 rounded-2xl p-4 text-sm focus:ring-2 focus:ring-purple-500 outline-none min-h-[80px] transition-all"
                      value={audioPrompt}
                      onChange={(e) => setAudioPrompt(e.target.value)}
                    />
                    <button 
                      onClick={generateAIAudio}
                      disabled={!audioPrompt || renderStatus.status !== RenderStatus.IDLE}
                      className="absolute bottom-3 right-3 p-2 bg-purple-500 rounded-xl hover:bg-purple-400 transition-colors disabled:opacity-50"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5.882V19.24a1.76 1.76 0 01-3.417.592l-2.147-6.15M18 13a3 3 0 100-6M5.436 13.683A4.001 4.001 0 017 6h1.832c4.1 0 7.625-1.234 9.168-3v14c-1.543-1.766-5.067-3-9.168-3H7a3.988 3.988 0 01-1.564-.317z" /></svg>
                    </button>
                  </div>
                  <p className="text-[10px] text-center text-slate-500 font-bold uppercase tracking-widest">— OR —</p>
                  <FileUploader 
                    label="Upload MP3 Podcast" 
                    accept="audio/*" 
                    selectedFileName={audio.name}
                    onFileSelect={(f) => setAudio({ file: f, previewUrl: URL.createObjectURL(f), name: f.name })}
                    icon={<svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19V6l12-3v13M9 19c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zm12-3c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zM9 10l12-3" /></svg>} 
                  />
                </div>
                {audio.previewUrl && (
                  <div className="bg-slate-950/80 rounded-2xl p-4 border border-white/5 flex items-center justify-between">
                    <div className="flex flex-col">
                      <span className="text-[10px] font-black text-purple-400 uppercase tracking-widest">Audio Track Connected</span>
                      <span className="text-xs text-slate-400 truncate max-w-[150px]">{audio.name}</span>
                    </div>
                    <div className="flex items-center gap-2">
                      <div className="w-1.5 h-6 bg-purple-500/20 rounded-full overflow-hidden flex flex-col justify-end">
                        <div className="w-full h-1/2 bg-purple-500 animate-pulse" />
                      </div>
                      <div className="w-1.5 h-8 bg-purple-500/20 rounded-full overflow-hidden flex flex-col justify-end">
                        <div className="w-full h-2/3 bg-purple-500 animate-pulse delay-75" />
                      </div>
                    </div>
                  </div>
                )}
              </div>
            </section>

            <div className="flex flex-col gap-6 pt-4">
              <div className="flex items-center gap-3 px-2">
                <input 
                  type="checkbox" 
                  id="policy" 
                  checked={agreed} 
                  onChange={(e) => setAgreed(e.target.checked)}
                  className="w-6 h-6 rounded-lg border-white/10 bg-slate-900 text-indigo-500 focus:ring-indigo-500 transition-all"
                />
                <label htmlFor="policy" className="text-[10px] font-black text-slate-500 uppercase tracking-widest select-none cursor-pointer">
                  Sync audio duration to video length
                </label>
              </div>

              <button 
                disabled={!image.file || !audio.file || !agreed || renderStatus.status !== RenderStatus.IDLE}
                onClick={startConversion}
                className="group relative w-full py-6 bg-gradient-to-r from-indigo-600 to-purple-600 disabled:from-slate-800 disabled:to-slate-800 disabled:text-slate-600 text-white rounded-3xl font-black text-xl shadow-2xl shadow-indigo-500/10 active:scale-[0.98] transition-all overflow-hidden"
              >
                <div className="absolute inset-0 bg-white/10 opacity-0 group-hover:opacity-100 transition-opacity" />
                <span className="relative z-10 italic">GENERATE CINEMATIC VIDEO</span>
              </button>
            </div>
          </div>
        )}

        {/* RENDERING STATE */}
        {renderStatus.status === RenderStatus.RENDERING && (
          <div className="bg-slate-900/50 backdrop-blur-2xl p-6 rounded-[2.5rem] shadow-3xl border border-white/5 space-y-6 animate-in zoom-in-95 duration-500">
            <div className="relative aspect-video rounded-3xl overflow-hidden bg-black shadow-2xl border border-white/10">
              <canvas ref={canvasRef} className="w-full h-full object-contain" />

              <div className="absolute inset-0 flex flex-col justify-end p-6 bg-gradient-to-t from-black/95 via-transparent to-transparent">
                <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center gap-2 bg-black/40 backdrop-blur-md px-3 py-1.5 rounded-full border border-white/10">
                    <div className="w-2.5 h-2.5 rounded-full bg-red-500 animate-pulse" />
                    <span className="text-[10px] font-black text-white uppercase tracking-[0.2em]">Live Render</span>
                  </div>
                  <span className="text-[10px] font-black text-indigo-300 uppercase tracking-widest bg-indigo-500/10 px-3 py-1.5 rounded-full border border-indigo-500/20">
                    {currentTimeFormatted} / {totalTimeFormatted}
                  </span>
                </div>

                <div className="relative h-14 w-full bg-white/5 rounded-2xl overflow-hidden border border-white/10 backdrop-blur-xl">
                   <div 
                    className="h-full bg-gradient-to-r from-indigo-600 to-purple-600 transition-all duration-300 flex items-center justify-end px-6 shadow-[0_0_40px_rgba(99,102,241,0.4)]" 
                    style={{ width: `${renderStatus.progress}%` }}
                   >
                     {renderStatus.progress > 20 && (
                       <span className="text-white font-black text-2xl italic drop-shadow-2xl">
                         {renderStatus.progress}%
                       </span>
                     )}
                   </div>
                   {renderStatus.progress <= 20 && (
                     <div className="absolute inset-0 flex items-center justify-center">
                        <span className="text-white/30 font-black text-sm italic tracking-widest">{renderStatus.progress}%</span>
                     </div>
                   )}
                </div>
              </div>
            </div>

            <div className="text-center space-y-2">
              <p className="text-xs text-indigo-400 font-black uppercase tracking-[0.3em]">{renderStatus.message}</p>
              <p className="text-[9px] text-slate-500 font-bold uppercase tracking-[0.4em]">Keep screen on • Matching original audio duration</p>
            </div>
          </div>
        )}

        {/* RESULTS STATE */}
        {resultVideoUrl && (
          <div className="bg-slate-900/50 backdrop-blur-2xl p-8 rounded-[2.5rem] shadow-3xl border border-white/5 space-y-8 animate-in fade-in slide-in-from-bottom-10 duration-700">
            <div className="text-center space-y-2">
              <div className="w-16 h-16 bg-emerald-500/10 border border-emerald-500/20 rounded-full flex items-center justify-center mx-auto mb-4">
                <svg className="w-8 h-8 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
              </div>
              <h2 className="text-3xl font-black text-white italic tracking-tighter uppercase">Mastered!</h2>
              <p className="text-slate-400 font-bold text-[10px] uppercase tracking-[0.4em]">Video duration synchronized to MP3</p>
            </div>

            <div className="aspect-video rounded-3xl overflow-hidden bg-black shadow-2xl border border-white/5">
              <video src={resultVideoUrl} controls className="w-full h-full" />
            </div>

            <div className="grid grid-cols-1 gap-4">
              <button 
                onClick={() => {
                   const a = document.createElement('a');
                   a.href = resultVideoUrl;
                   a.download = `VocalCanvas_${Date.now()}.mp4`;
                   a.click();
                }}
                className="w-full py-6 bg-gradient-to-r from-emerald-600 to-teal-600 text-white rounded-3xl font-black text-xl shadow-2xl active:scale-[0.98] transition-all flex items-center justify-center gap-4 italic"
              >
                <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                DOWNLOAD HD MP4
              </button>
              <button 
