        const h = img.height * ratio;

        const offsetX = (1280 - w) / 2 + (Math.cos(time * 0.1) * 10);
        const offsetY = (720 - h) / 2 + (Math.sin(time * 0.08) * 10);

        ctx.drawImage(img, offsetX, offsetY, w, h);

