      });

      const chunks: Blob[] = [];
      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunks.push(e.data);
      };

      recorder.onstop = () => {
        const finalBlob = new Blob(chunks, { type: mimeType });
        const url = URL.createObjectURL(finalBlob);
        setResultVideoUrl(url);
        setRenderStatus({ status: RenderStatus.COMPLETED, progress: 100, message: 'Export Complete' });
        if (wakeLockRef.current) wakeLockRef.current.release();
      };

      const draw = () => {
        if (!ctx || !audioRef.current) return;

        // Background color
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(0, 0, 1280, 720);

        // Draw Image with Cover fit
        const ratio = Math.max(1280 / img.width, 720 / img.height);
        const w = img.width * ratio;
        const h = img.height * ratio;
        const x = (1280 - w) / 2;
        const y = (720 - h) / 2;
        ctx.drawImage(img, x, y, w, h);

        const time = audioRef.current.currentTime;
        const duration = audioRef.current.duration;
        const p = Math.floor((time / duration) * 100);

        setCurrentTimeFormatted(formatTime(time));
        setTotalTimeFormatted(formatTime(duration));

        // High frequency progress update
        setRenderStatus(prev => ({ 
          ...prev,
          progress: isNaN(p) ? 0 : Math.min(99, p),
          message: `Recording: ${formatTime(time)} / ${formatTime(duration)}`
        }));

        if (audioRef.current.ended || time >= duration) {
          setTimeout(() => {
            if (recorder.state === 'recording') recorder.stop();
            if (renderLoopRef.current) cancelAnimationFrame(renderLoopRef.current);
          }, 1000); // 1s buffer to ensure we catch the end
          return;
        }
        renderLoopRef.current = requestAnimationFrame(draw);
      };

      // Set playback to 1.0 to ensure duration matches perfectly
      audioRef.current.currentTime = 0;
      audioRef.current.playbackRate = 1.0; 
      audioRef.current.muted = false; 

      await audioCtx.resume();
      recorder.start();
      await audioRef.current.play();
      draw();

