import React, { useRef } from 'react';

interface FileUploaderProps {
  label: string;
  accept: string;
  icon: React.ReactNode;
  onFileSelect: (file: File) => void;
  selectedFileName?: string;
  previewUrl?: string | null;
}

const FileUploader: React.FC<FileUploaderProps> = ({ 
  label, 
  accept, 
  icon, 
  onFileSelect, 
  selectedFileName,
  previewUrl
}) => {
  const inputRef = useRef<HTMLInputElement>(null);

  const handleClick = () => {
    inputRef.current?.click();
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      onFileSelect(file);
    }
  };

  return (
    <div 
      onClick={handleClick}
      className={`
        relative group cursor-pointer border-2 border-dashed rounded-[32px] py-12 px-6 flex flex-col items-center justify-center transition-all duration-500 active:scale-[0.98]
        ${selectedFileName 
          ? 'border-cyan-500 bg-cyan-950/20 neon-cyan shadow-inner' 
          : 'border-slate-800 bg-slate-900/40 hover:border-blue-500 hover:bg-slate-900/60 shadow-lg'}
      `}
    >
      <input 
        type="file" 
        ref={inputRef} 
        onChange={handleChange} 
        accept={accept} 
        className="hidden" 
      />

      <div className={`
        w-20 h-20 rounded-2xl flex items-center justify-center transition-all duration-700 overflow-hidden mb-4
        ${selectedFileName ? 'bg-cyan-500 text-white shadow-[0_0_20px_rgba(34,211,238,0.6)]' : 'bg-slate-800 text-slate-500'}
      `}>
        {previewUrl ? (
          <img src={previewUrl} alt="Preview" className="w-full h-full object-cover" />
