import React, { useState, useRef } from 'react';
import FileUploader from './components/FileUploader';
import { FileState, RenderStatus, RenderingProgress } from './types';

const App: React.FC = () => {
  const [image, setImage] = useState<FileState>({ file: null, previewUrl: null, name: '' });
  const [audio, setAudio] = useState<FileState>({ file: null, previewUrl: null, name: '' });
  const [agreed, setAgreed] = useState(false);
  const [renderStatus, setRenderStatus] = useState<RenderingProgress>({
    status: RenderStatus.IDLE,
    progress: 0,
    message: ''
  });
  const [resultVideoUrl, setResultVideoUrl] = useState<string | null>(null);
  const [totalTimeFormatted, setTotalTimeFormatted] = useState('0:00');

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const audioRef = useRef<HTMLAudioElement>(null);
  const renderLoopRef = useRef<number | null>(null);
  const wakeLockRef = useRef<any>(null);
  const recorderRef = useRef<MediaRecorder | null>(null);

  const formatTime = (seconds: number) => {
    if (isNaN(seconds) || !isFinite(seconds)) return '0:00';
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const stopRecording = () => {
    if (recorderRef.current && recorderRef.current.state === 'recording') {
      recorderRef.current.stop();
    }
    if (renderLoopRef.current) {
      cancelAnimationFrame(renderLoopRef.current);
    }
    if (wakeLockRef.current) {
      try { wakeLockRef.current.release(); } catch(e) {}
    }
  };

  const startConversion = async () => {
    if (!image.file || !audio.file || !audioRef.current || !agreed) return;

    try {
      setRenderStatus({
        status: RenderStatus.RENDERING,
        progress: 0,
        message: 'Master Bridge Active'
      });

      if ('wakeLock' in navigator) {
        try { wakeLockRef.current = await (navigator as any).wakeLock.request('screen'); } catch (e) {}
      }

      const canvas = canvasRef.current!;
      const ctx = canvas.getContext('2d', { alpha: false })!;
      canvas.width = 1280;
      canvas.height = 720;

      const img = new Image();
      img.src = image.previewUrl!;
      await new Promise((r) => img.onload = r);

      const AudioContextClass = (window.AudioContext || (window as any).webkitAudioContext);
      const audioCtx = new AudioContextClass();
      const source = audioCtx.createMediaElementSource(audioRef.current);
      const dest = audioCtx.createMediaStreamDestination();

      source.connect(audioCtx.destination);
      source.connect(dest);

      const videoStream = canvas.captureStream(30); 
      const combinedStream = new MediaStream([
        ...videoStream.getVideoTracks(),
        ...dest.stream.getAudioTracks()
      ]);

      const mimeType = MediaRecorder.isTypeSupported('video/mp4') 
        ? 'video/mp4' 
        : (MediaRecorder.isTypeSupported('video/webm;codecs=vp9,opus') 
          ? 'video/webm;codecs=vp9,opus' 
          : 'video/webm');

      const recorder = new MediaRecorder(combinedStream, { 
        mimeType, 
        videoBitsPerSecond: 8000000, 
        audioBitsPerSecond: 320000  
      });

      recorderRef.current = recorder;
      const chunks: Blob[] = [];
      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunks.push(e.data);
      };

      recorder.onstop = () => {
        const finalBlob = new Blob(chunks, { type: mimeType });
        const url = URL.createObjectURL(finalBlob);
        setResultVideoUrl(url);
        setRenderStatus({ status: RenderStatus.COMPLETED, progress: 100, message: 'HD Master Ready' });
      };

      const draw = () => {
        if (!ctx || !audioRef.current) return;

        ctx.fillStyle = '#000000';
        ctx.fillRect(0, 0, 1280, 720);

        const ratio = Math.max(1280 / img.width, 720 / img.height);
        const w = img.width * ratio;
        const h = img.height * ratio;
        const x = (1280 - w) / 2;
        const y = (720 - h) / 2;
        ctx.drawImage(img, x, y, w, h);

        const time = audioRef.current.currentTime;
        const duration = audioRef.current.duration;
        const p = Math.floor((time / duration) * 100);

        setRenderStatus(prev => ({ 
          ...prev,
          progress: isNaN(p) ? 0 : Math.min(99, p),
          message: `${formatTime(time)} / ${formatTime(duration)}`
        }));

        if (audioRef.current.ended || time >= duration) {
          stopRecording();
          return;
        }
        renderLoopRef.current = requestAnimationFrame(draw);
      };

      audioRef.current.currentTime = 0;
      audioRef.current.playbackRate = 1.0; 
      audioRef.current.muted = false; 

      await audioCtx.resume();
      recorder.start();
      await audioRef.current.play();
      setTotalTimeFormatted(formatTime(audioRef.current.duration));
      draw();

    } catch (err) {
      console.error(err);
      setRenderStatus({ status: RenderStatus.ERROR, progress: 0, message: 'System Error' });
    }
  };

  return (
    <div className="min-h-screen text-slate-100 flex flex-col font-sans selection:bg-blue-900 antialiased">
      {/* Header */}
      <header className="bg-slate-950/80 backdrop-blur-xl border-b border-slate-800 p-6 flex items-center justify-between shadow-2xl sticky top-0 z-50">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center neon-blue rotate-6 shadow-blue-500/20">
            <svg className="w-7 h-7 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
          </div>
          <h1 className="text-2xl font-black tracking-tighter text-white italic">VocalCanvas</h1>
        </div>
        <div className="flex items-center gap-4">
           <div className="px-4 py-1.5 bg-blue-900/40 border border-blue-500/50 rounded-full">
              <span className="text-[10px] font-black text-blue-400 uppercase tracking-[0.2em] neon-text-blue">STABLE V2.5</span>
           </div>
           <div className="w-2.5 h-2.5 bg-cyan-400 rounded-full animate-pulse shadow-[0_0_12px_rgba(34,211,238,0.8)]" />
        </div>
      </header>

      <main className="flex-1 max-w-2xl mx-auto w-full px-6 py-12 space-y-12">
        {renderStatus.status === RenderStatus.IDLE && !resultVideoUrl && (
          <div className="space-y-12 animate-in fade-in slide-in-from-bottom-8 duration-700">
            <div className="text-center space-y-4">
              <h2 className="text-5xl font-black text-white leading-none tracking-tighter">
                Convert MP3 to <br/>
                <span className="text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 to-blue-600 neon-text-blue">HD Video</span>
              </h2>
              <p className="text-slate-500 text-sm font-bold uppercase tracking-[0.3em] italic opacity-80">1:1 Audio-Visual Fidelity Guaranteed</p>
            </div>

            <section className="bg-slate-900/40 backdrop-blur-md p-10 rounded-[48px] shadow-[0_0_50px_rgba(0,0,0,0.5)] border border-slate-800 space-y-8 relative overflow-hidden">
              <div className="space-y-6">
                <FileUploader 
                  label="1. Background Image" 
                  accept="image/*" 
                  selectedFileName={image.name}
                  previewUrl={image.previewUrl}
                  onFileSelect={(f) => setImage({ file: f, previewUrl: URL.createObjectURL(f), name: f.name })}
                  icon={<svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>} 
                />

                <FileUploader 
                  label="2. Audio File (MP3)" 
                  accept="audio/*" 
                  selectedFileName={audio.name}
                  onFileSelect={(f) => setAudio({ file: f, previewUrl: null, name: f.name })}
                  icon={<svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19V6l12-3v13M9 19c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zm12-3c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zM9 10l12-3" /></svg>} 
                />
              </div>

              <div className="pt-10 border-t border-slate-800 space-y-8">
                <div 
