                    <svg className="w-6 h-6 animate-pulse" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                  </span>
                  <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent skew-x-[-20deg] group-hover:translate-x-full transition-transform duration-700 -translate-x-full" />
                </button>
              </div>
            </section>
          </div>
        )}

        {renderStatus.status === RenderStatus.RENDERING && (
          <div className="bg-slate-900/60 backdrop-blur-2xl p-10 rounded-[64px] shadow-[0_0_100px_rgba(37,99,235,0.15)] border border-slate-800 space-y-12 animate-in zoom-in-95 duration-700">
            <div className="aspect-video rounded-[40px] overflow-hidden bg-black shadow-2xl relative border-2 border-slate-800">
              <canvas ref={canvasRef} className="w-full h-full object-contain opacity-50" />
